
# groq_responses.py
"""
Simplified Groq-compatible replacement for OpenAI Responses wrapper.
Removes unsupported APIs: responses, vector_stores, files.create.
Uses chat.completions only.
"""
import os, httpx
from dataclasses import dataclass, field
from typing import Optional, Dict, Any, List
from groq import Groq, AsyncGroq
from agno.models.base import Model
from agno.models.message import Message
from agno.models.response import ModelResponse
from agno.exceptions import ModelAuthenticationError

@dataclass
class LLMResponses(Model):
    id:str="llama-3.3-70b-versatile"
    provider:str="groq"
    temperature:float=0.7
    api_key:Optional[str]=None
    client:Optional[Groq]=None
    async_client:Optional[AsyncGroq]=None
    role_map:Dict[str,str]=field(default_factory=lambda:{
        "system":"system","user":"user","assistant":"assistant"
    })

    def _get_client_params(self):
        key=self.api_key or os.getenv("GROQ_API_KEY")
        if not key:
            raise ModelAuthenticationError(
                message="Set GROQ_API_KEY",model_name=self.provider
            )
        return {"api_key":key}

    def get_client(self):
        if self.client: return self.client
        self.client=Groq(**self._get_client_params())
        return self.client

    def get_async_client(self):
        if self.async_client: return self.async_client
        self.async_client=AsyncGroq(**self._get_client_params())
        return self.async_client

    def _format_messages(self,messages:List[Message]):
        out=[]
        for m in messages:
            out.append({
                "role": self.role_map.get(m.role,"user"),
                "content": str(m.content or "")
            })
        return out

    def invoke(self,messages,assistant_message=None,**kwargs):
        resp=self.get_client().chat.completions.create(
            model=self.id,
            messages=self._format_messages(messages),
            temperature=self.temperature
        )
        mr=ModelResponse()
        mr.role="assistant"
        mr.content=resp.choices[0].message.content
        return mr

    async def ainvoke(self,messages,assistant_message=None,**kwargs):
        resp=await self.get_async_client().chat.completions.create(
            model=self.id,
            messages=self._format_messages(messages),
            temperature=self.temperature
        )
        mr=ModelResponse()
        mr.role="assistant"
        mr.content=resp.choices[0].message.content
        return mr
